// ─────────────────────────────────────────────────────────────────────────────
// src/hooks/useAppState.js — UPDATED with email login + addEmployee + addLeaveType
// ─────────────────────────────────────────────────────────────────────────────

import { useState, useEffect, useCallback } from "react";
import * as api from "../services/api";

export function useAppState() {
  const [user, setUser] = useState(null);
  const [activeTab, setActiveTab] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [loading, setLoading] = useState(true);

  const [leaves, setLeaves] = useState([]);
  const [holidays, setHolidays] = useState([]);
  const [employees, setEmployees] = useState([]);
  const [balances, setBalances] = useState({});
  const [leaveTypes, setLeaveTypes] = useState([]);

  // ── Load all data ───────────────────────────────────────────────────────────
  const fetchAllData = useCallback(async () => {
    try {
      const [leavesData, holidaysData, employeesData, balancesData, leaveTypesData] =
        await Promise.all([
          api.getLeaves(),
          api.getHolidays(),
          api.getEmployees(),
          api.getBalances(),
          api.getLeaveTypes(),
        ]);
      setLeaves(leavesData);
      setHolidays(holidaysData);
      setEmployees(employeesData);
      setBalances(balancesData);
      setLeaveTypes(leaveTypesData);
    } catch (err) {
      console.error("Failed to fetch data:", err);
    }
  }, []);

  // ── Restore session ─────────────────────────────────────────────────────────
  useEffect(() => {
    const token = localStorage.getItem("auth_token");
    if (token) {
      api.getUser()
        .then((userData) => { setUser(userData); return fetchAllData(); })
        .catch(() => localStorage.removeItem("auth_token"))
        .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, [fetchAllData]);

  // ── Auth — Demo login (role cards) ────────────────────────────────────────
  const login = async (selectedUser) => {
    try {
      const userData = await api.loginAs(selectedUser.id);
      setUser(userData);
      setActiveTab("dashboard");
      await fetchAllData();
    } catch (err) {
      console.error("Login failed:", err);
      alert("Login failed. Please check the backend is running.");
    }
  };

  // ── Auth — Email + Password login (NEW) ───────────────────────────────────
  const loginWithEmail = async (email, password) => {
    try {
      const userData = await api.loginWithEmail(email, password);
      setUser(userData);
      setActiveTab("dashboard");
      await fetchAllData();
    } catch (err) {
      console.error("Email login failed:", err);
      // Re-throw so Login.jsx can show error
      throw new Error(err.response?.data?.message || "Invalid email or password. Please try again.");
    }
  };

  const logout = async () => {
    try { await api.logout(); } catch {}
    setUser(null);
    setActiveTab("dashboard");
    setLeaves([]);
    setHolidays([]);
    setEmployees([]);
    setBalances({});
    setLeaveTypes([]);
  };

  // ── Leave actions ────────────────────────────────────────────────────────────
  const submitLeave = async (form) => {
    try {
      const result = await api.applyLeave({
        leaveType: form.leaveType,
        startDate: form.startDate,
        endDate: form.endDate,
        reason: form.reason,
      });
      if (result.success) {
        const [leavesData, balancesData] = await Promise.all([api.getLeaves(), api.getBalances()]);
        setLeaves(leavesData);
        setBalances(balancesData);
      }
      return result;
    } catch (err) {
      const message = err.response?.data?.message || "Failed to submit leave.";
      alert(message);
      return { success: false, message };
    }
  };

  const cancelLeave = async (id) => {
    try {
      await api.cancelLeave(id);
      setLeaves((prev) => prev.map((l) => (l.id === id ? { ...l, status: "cancelled" } : l)));
    } catch (err) {
      alert(err.response?.data?.message || "Failed to cancel leave.");
    }
  };

  const reviewLeave = async (leaveId, action, comment, reviewerId) => {
    try {
      await api.reviewLeave(leaveId, action, comment);
      const [leavesData, balancesData] = await Promise.all([api.getLeaves(), api.getBalances()]);
      setLeaves(leavesData);
      setBalances(balancesData);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to review leave.");
    }
  };

  // ── Holiday actions ──────────────────────────────────────────────────────────
  const addHoliday = async (holidayData) => {
    try {
      const newHoliday = await api.addHoliday(holidayData);
      setHolidays((prev) => [...prev, newHoliday]);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to add holiday.");
    }
  };

  const deleteHoliday = async (id) => {
    try {
      await api.deleteHoliday(id);
      setHolidays((prev) => prev.filter((h) => h.id !== id));
    } catch (err) {
      alert(err.response?.data?.message || "Failed to delete holiday.");
    }
  };

  // ── Employee actions ──────────────────────────────────────────────────────────
  const addEmployee = async (form) => {
    try {
      const result = await api.addEmployee(form);
      if (result.success) {
        const [empData, balData] = await Promise.all([api.getEmployees(), api.getBalances()]);
        setEmployees(empData);
        setBalances(balData);
      }
      return result;
    } catch (err) {
      const message = err.response?.data?.message || "Failed to add employee.";
      throw new Error(message);
    }
  };

  // ── Leave Type actions ────────────────────────────────────────────────────────
  const addLeaveType = async (form) => {
    try {
      const result = await api.addLeaveType(form);
      if (result.success) {
        const [ltData, balData] = await Promise.all([api.getLeaveTypes(), api.getBalances()]);
        setLeaveTypes(ltData);
        setBalances(balData);
      }
      return result;
    } catch (err) {
      const message = err.response?.data?.message || "Failed to add leave type.";
      throw new Error(message);
    }
  };

  // ── Derived ──────────────────────────────────────────────────────────────────
  const pendingCount = leaves.filter((l) => l.status === "pending").length;

  return {
    user, activeTab, sidebarOpen,
    leaves, holidays, employees, balances, leaveTypes, pendingCount, loading,

    setActiveTab, setSidebarOpen,

    login, loginWithEmail, logout,       // loginWithEmail is NEW

    submitLeave, cancelLeave, reviewLeave,

    addHoliday, deleteHoliday,

    addEmployee,
    addLeaveType,
  };
}
